import{_ as i,a as o,b as u,c as n,d as s}from"./TestNavigationButtons-bc239026.js";import{_ as a}from"./QuestionTemp4.vue_vue_type_script_setup_true_lang-fa9f34ce.js";import{S as c}from"./SeihoTestLayout-97e0d25e.js";import{o as y,c as v,w as r,b as p,a as e}from"./app-5184c8df.js";import"./AdSenseUnit.vue_vue_type_script_setup_true_lang-fab1203d.js";const k={class:"bg-gray-100 text-gray-800 py-10"},b={class:"max-w-4xl mx-auto mt-4 space-y-2"},t="生命保険計理",l="2024年度 フォームC",P={__name:"Keiri2024c",setup(T){return(m,f)=>(y(),v(c,{title:t},{default:r(()=>[p("section",k,[e(i,{title:t,description:l}),p("div",b,[e(a,{questionNumber:1,title:t,subject:l,contents:[{answer:"0.98925",questionTitle:"生存率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"生存率とは、「ある年齢の人が、次の年齢まで生き残る割合」のこと。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["生存率 ＝ 期末の生存数 ÷ 期初の生存数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["生存率（45歳 → 50歳）","＝ 50歳の生存数 ÷ 45歳の生存数","＝ 96,319 ÷ 97,336 ＝ 0.989246"]},{type:"result",value:"▶ 答え 0.98925（小数第6位を四捨五入）"}]},{answer:"93,714",questionTitle:"生存数",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"「10年後に何人残るか」は、今の人数に10年間生き残る割合（生存率）を掛けることで求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formula",value:"N年後の生存者数 = 基準年齢の人数 × 生存率（問１参照）"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"10年後の生存者数"},{type:"formulaBlock",value:["基準年齢（55歳）の人数 × 生存率（55歳 → 65歳）","= 100,000 × 88,751 ÷ 94,704 = 93,714.0"]},{type:"result",value:"▶ 答え 93,714（小数第1位を四捨五入）"}]},{answer:"1.16",questionTitle:"平均余命",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"平均余命とは、その年齢の全員がこれから生きる年数を全部足して、今の人数で割ったもの。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["延べ生存年数 ＝ 死亡数 × 平均生存年数","平均余命 ＝ 延べ生存年数の合計 ÷ 生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 各年齢の延べ生存年数"},{type:"note",value:"各年齢の死亡者は、その年齢内で平均<strong>0.5年</strong>生存したとみなして計算する。"},{type:"formulaBlock",value:["105歳：30.877 × 0.5 ＝ 15.44","106歳：13.8961 × 1.5 ＝ 20.84","107歳：5.6633 × 2.5 ＝ 14.16","108歳：2.0682 × 3.5 ＝ 7.24","109歳：0.9156 × 4.5 ＝ 4.12"]},{type:"text",value:"② 105歳～109歳の延べ生存年数の合計"},{type:"note",value:"105歳以上の全員が、合計で何年分生きたかを合算する。"},{type:"formulaBlock",value:["15.44 + 20.84 + 14.16 + 7.24 + 4.12 ＝ 61.8"]},{type:"text",value:"③ 105歳の平均余命"},{type:"formulaBlock",value:["105歳～109歳の延べ生存年数の合計 ÷ 105歳の生存者数","= 61.8 ÷ 53.420","= 1.156"]},{type:"result",value:"▶ 答え 1.16（小数第3位を四捨五入）"}]},{answer:"1,368,176",questionTitle:"保険金総額の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"1年定期保険では、1年間に死亡した人に保険金を支払う。したがって、まず死亡者全員に支払う保険金の合計額を出し、支払い時点を年央（期央）とみなして、期央払現価率で割り引いて現価を求める。"},{type:"note",value:"※期央払現価率とは、年の真ん中で支払われると仮定したときの割引係数。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["合計保険金額 ＝ 保険金 × 死亡数","現価 ＝ 合計保険金額 × 期央払現価率（利率1.0%）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 合計保険金額"},{type:"formulaBlock",value:["保険金（500万円） × 死亡数（50歳）","＝ 5,000千円 × 275人","＝ 1,375,000千円"]},{type:"text",value:"② 現価（年央払）"},{type:"formulaBlock",value:["合計保険金額 × 期央払現価率（利率1.0%）","＝ 1,375,000千円 × 0.995037","＝ 1,368,175.8千円"]},{type:"result",value:"▶ 答え：1,368,176千円（千円未満四捨五入）"}]},{answer:"14,200",questionTitle:"純保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"純保険料は、必要な保険金総額の現価を、加入者全員で負担する額。したがって、必要な現価を年始生存者数で割る。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["純保険料 ＝ 必要な現価 ÷ 年始生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["純保険料","＝ 必要な現価（問４の解） ÷ 50歳の年始生存者数","＝ 1,368,176千円 ÷ 96,319人","＝ 14,204円"]},{type:"result",value:"▶ 答え 14,200円（10円未満四捨五入）"}]}],labels:["イ","ク","ウ","コ","オ"]}),e(a,{questionNumber:6,title:t,subject:l,contents:[{answer:"4,517",questionTitle:"複利計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"複利では、元金に利息が組み込まれながら増えていく。まず6か月後の元利合計を求め、そこから元金を差し引いて利息を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 ＝ 元金 × (1 + 利率)<sup>運用期間</sup>","利息 ＝ 元利合計 − 元金"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：500,000円","月利：0.15％ ＝ 0.0015","運用期間：6か月"]},{type:"text",value:"① 元利合計"},{type:"formulaBlock",value:["＝ 500,000円 × (1 + 0.0015)<sup>6</sup>","＝ 500,000円 × 1.0090338","＝ 504,516.9円"]},{type:"text",value:"② 利息"},{type:"formulaBlock",value:["＝ 504,516.9円 − 500,000円","＝ 4,516.9円"]},{type:"result",value:"▶ 答え 4,517円（円未満四捨五入）"}]},{answer:"528,696",questionTitle:"複利計算（半年複利）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年利1.4％で半年複利の場合、半年ごとに0.7％ずつ増える。4年間では半年が8回あるため、半年利率で8回複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 ＝ 元金 × (1 + 期間利率)<sup>複利回数</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：500,000円","年利：1.4％","半年利率：＝ 1.4％ ÷ 2 ＝ 0.7％ ＝ 0.007","複利回数：＝ 4年 × 年2回 ＝ 8回"]},{type:"formulaBlock",value:["元利合計","＝ 500,000円 × (1 + 0.007)<sup>8</sup>","＝ 500,000円 × 1.0573912","＝ 528,695.6円"]},{type:"result",value:"▶ 答え 528,696円（円未満四捨五入）"}]},{answer:"1.21",questionTitle:"実利率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"実利率とは、1年間に実際どれだけ増えるかを示す利率。名称利率が年率でも、年に複数回利息が付く場合は、その回数分だけ複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["実利率 ＝（ 1 + 名称利率 ÷ 転化回数）<sup>転化回数</sup> - 1"]},{type:"note",value:"転化回数：1年間に利息を元金に繰り入れる回数"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 1回あたりの利率"},{type:"formulaBlock",value:["＝ 0.012 ÷ 4","＝ 0.003"]},{type:"text",value:"② 実利率"},{type:"formulaBlock",value:["＝ (1 + 0.003)<sup>4</sup> − 1","＝ 1.01205 − 1","＝ 0.01205 ＝ 1.205％"]},{type:"result",value:"▶ 答え 1.21％（小数第3位を四捨五入）"}]},{answer:"1.83",questionTitle:"年平均利回り",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"まず、3年間の複利でどれだけ増えたか（総利回り）を求める。その後、それを3年で平均したものが年平均利回り。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["総利回り ＝ (1 + 複利利率)<sup>期間</sup> − 1","年平均利回り ＝ 総利回り ÷ 期間"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["複利利率：1.8％ ＝ 0.018","投資期間：3年"]},{type:"text",value:"① 総利回り"},{type:"formulaBlock",value:["＝ (1 + 0.018)<sup>3</sup> − 1","＝ 1.05497 − 1","＝ 0.05497"]},{type:"text",value:"② 年平均利回り"},{type:"formulaBlock",value:["＝ 0.05497 ÷ 3","＝ 0.01832 ＝ 1.832％"]},{type:"result",value:"▶ 答え 1.83％（小数第3位を四捨五入）"}]},{answer:"4,618,507",questionTitle:"現在必要資金の計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"将来500万円を得るために、今いくら必要かを求める問題。将来価値がわかっているので、複利を逆算（割り戻す）して現在価値を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["現在価値 ＝ 将来価値 ÷ (1 + 利率)<sup>期間</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["将来価値：5,000,000円","年利率：1.6％ ＝ 0.016","期間：5年"]},{type:"formulaBlock",value:["現在価値","＝ 5,000,000 ÷ (1 + 0.016)<sup>5</sup>","＝ 5,000,000 ÷ 1.082608…","＝ 4,618,506.8…"]},{type:"result",value:"▶ 答え 4,618,507円（円未満四捨五入）"}]}],labels:["オ","ク","ア","ウ","コ"]}),e(o,{questionNumber:3,title:t,subject:l,questionTitle:"責任準備金の定義",contents:["純保険料","全払込期間","定期保険","後半","ゼロ"],labels:["オ","キ","ケ","ウ","ア"]}),e(o,{questionNumber:4,title:t,subject:l,questionTitle:"保険料積立金",contents:["将来法","一致する","貯蓄保険料","付加保険料","チルメル"],labels:["キ","ウ","ク","コ","ケ"]}),e(a,{questionNumber:21,title:t,subject:l,contents:[{answer:"6,405,460千円",questionTitle:"死亡保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"保険期間（55〜57歳）の各年齢で死亡した場合、死亡保険金が支払われる。支払いは年央（期央）と仮定されるため、各年齢の「死亡保険金 × 死亡数」を期央払現価率で割り引き、現価を合計する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["各年齢の死亡保険金現価 = 死亡保険金 × 死亡数 × 期央払現価率","死亡保険金現価の合計 = 各年齢の死亡保険金現価の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["死亡保険金：500万円 = 5,000千円","保険期間：3年（55〜57歳）","支払い：年央（期央）と仮定"]},{type:"text",value:"① 各年齢の死亡保険金現価"},{type:"formulaBlock",value:["55歳：5,000千円 × 400 × 0.995037 = 1,990,074千円","56歳：5,000千円 × 432 × 0.985185 = 2,128,000千円","57歳：5,000千円 × 469 × 0.975431 = 2,287,386千円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["死亡保険金現価の合計","= 1,990,074 + 2,128,000 + 2,287,386","= 6,405,460千円"]},{type:"result",value:"▶ 答え 6,405,460千円"}]},{answer:"453,280,089千円",questionTitle:"満期保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"満期保険金は、保険期間満了時（3年後）に生存している人に支払われる。したがって、まず 3年後の生存者数 × 保険金額 で将来の支払総額を求め、それを 期末払現価率 で割り引いて現価を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["満期保険金の現価 = 3年後の生存者数 × 保険金額 × 期末払現価率（3年）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：500万円 = 5,000千円","3年後（58歳）の生存数：93,403人","3年の期末払現価率：0.970590"]},{type:"formulaBlock",value:["満期保険金の現価","= 93,403 × 5,000 × 0.970590","= 453,280,088.850千円"]},{type:"result",value:"▶ 答え 453,280,089千円（千円未満四捨五入）"}]},{answer:"11,838,000千円",questionTitle:"予定事業費の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"予定事業費が「保険金1000円につき25円」と与えられているので、まず 1人あたりの予定事業費を求める。その後、加入時（55歳）の生存者数を掛けて、全体の予定事業費（現価）を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["1人あたりの予定事業費 = 保険金額 ×（25 ÷ 1000）","予定事業費の現価（合計） = 1人あたりの予定事業費 × 加入時の生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：500万円 = 5,000千円","予定事業費：保険金1000円につき25円 = 25 ÷ 1000","55歳の生存数：94,704人"]},{type:"text",value:"① 1人あたりの予定事業費"},{type:"formulaBlock",value:["= 5,000千円 ×（25 ÷ 1000）","= 5,000 × 0.025","= 125千円"]},{type:"text",value:"② 予定事業費の現価（合計）"},{type:"formulaBlock",value:["= 125千円 × 94,704人","= 11,838,000千円"]},{type:"result",value:"▶ 答え 11,838,000千円（千円未満四捨五入）"}]},{answer:"1,683,420円",questionTitle:"養老保険の年払営業保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年払営業保険料 P は、収支相当の原則（収入現価=支出現価）で求める。"},{type:"text",value:"収入現価：各年齢で生存している人が払う保険料 P を、期始払として現価に直して合計する"},{type:"text",value:"支出現価：死亡保険金・満期保険金・予定事業費の現価を合計する（問21〜23の結果）"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["収支相当の原則：収入現価 = 支出現価","各年齢の収入現価（期始払） = 生存数 × P × 期始払現価率","支出現価 = 死亡保険金現価 + 満期保険金現価 + 予定事業費現価"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 収入現価（55〜57歳、期始払）"},{type:"formulaBlock",value:["55歳：P × 94,704 × 1.000000 = 94,704P","56歳：P × 94,305 × 0.990099 = 93,371P","57歳：P × 93,873 × 0.980296 = 92,023P"]},{type:"formulaBlock",value:["収入現価の合計","= 94,704P + 93,371P + 92,023P","= 280,098P"]},{type:"text",value:"② 支出現価（問21〜23より）"},{type:"formulaBlock",value:["死亡保険金の現価（問21）= 6,405,460千円","満期保険金の現価（問22）= 453,280,089千円","予定事業費の現価（問23）= 11,838,000千円"]},{type:"formulaBlock",value:["支出現価","= 6,405,460 + 453,280,089 + 11,838,000","= 471,523,549千円 = 471,523,549,000円"]},{type:"text",value:"③ 収支相当の原則より P を求める"},{type:"formulaBlock",value:["収入現価 = 支出現価 より","280,098P = 471,523,549,000円","P = 471,523,549,000円 ÷ 280,098","P = 1,683,423円"]},{type:"result",value:"▶ 答え 1,683,420円（10円未満四捨五入）"}]},{answer:"1,097,000円",questionTitle:"払済保険金額",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"払済保険とは、解約返戻金をもとに、同条件の養老保険を一時払で買い直すものである。したがって、解約返戻金で購入できる保険金額を比例計算で求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["払済保険金 ＝ 解約返戻金 ×（保険金額 ÷ 一時払保険料）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["解約返戻金：858,000円","保険金額：3,000,000円","一時払保険料：2,345,580円"]},{type:"formulaBlock",value:["払済保険金","＝ 858,000 ×（3,000,000 ÷ 2,345,580）","＝ 858,000 × 1.279…","＝ 1,097,383円"]},{type:"result",value:"▶ 答え 1,097,000円（千円未満四捨五入）"}]}],labels:["ア","イ","ウ","イ","ア"]}),e(u,{questionNumber:26,title:t,subject:l,questionTitle:"死亡表の種類",contents:["正しい","簡易生命表 → 完全生命表","正しい"]}),e(u,{questionNumber:27,title:t,subject:l,questionTitle:"剰余金の発生源",contents:["正しい","利差益は責任準備金に反比例 → 利差益は責任準備金に比例<br>契約初期は多く → 契約初期は少なく<br>経過年数が長くなるほど少なく → 経過年数が長くなるほど多く","正しい"]}),e(u,{questionNumber:28,title:t,subject:l,questionTitle:"事業年度末責任準備金",contents:["3区分 → 4区分（払戻積立金が含まれる）","正しい","正しい"]}),e(u,{questionNumber:29,title:t,subject:l,questionTitle:"契約転換制度",contents:["正しい","正しい","新契約費部分を含む → 新契約費部分を含まない"]}),e(u,{questionNumber:30,title:t,subject:l,questionTitle:"団体年金保険の数理",contents:["即時積増方式 → 一時払積増方式","正しい","正しい"]}),e(n,{questionNumber:31,title:t,subject:l,items:[{questionTitle:"死亡率",content:"基本死亡率 → 粗死亡率<br>応用死亡率 → 補整後死亡率"},{questionTitle:"現価",content:"期始払現価 → 期末払現価"},{questionTitle:"予定利率",content:"正しい"},{questionTitle:"分割払営業保険料",content:"営業保険料額を下回る → 営業保険料額を上回る（分割払は予定利息減少・事務費増加のため）"},{questionTitle:"計算基礎の変化と純保険料の変化",content:"正しい"},{questionTitle:"高額割引",content:"正しい"},{questionTitle:"解約返戻金の算式",content:"正しい"},{questionTitle:"利差配当付保険",content:"経過年数にかかわらず → 一定年数経過している場合に"},{questionTitle:"リスクヘッジ",content:"正しい"},{questionTitle:"最低保証機能",content:"3つのタイプ → 4つのタイプ（最低解約保証タイプを含む）"},{questionTitle:"資産の平均利回り",label:"オ",content:""},{questionTitle:"保険料の計算原理",label:"ア",content:"現価"},{questionTitle:"保険料の計算基礎",label:"ウ",content:"保険金に比例させる"},{questionTitle:"純保険料の計算式",label:"エ",content:"（1 + 予定利率）"},{questionTitle:"払済保険",label:"ア",content:"養老保険"},{questionTitle:"配当準備金繰入",label:"ア",content:"定款"},{questionTitle:"変額保険の仕組み",label:"オ",content:""},{questionTitle:"配当金の計算方法",label:"オ",content:""},{questionTitle:"特別勘定の位置付け",label:"エ",content:"を禁止されている"},{questionTitle:"団体定期保険の保険料",label:"オ",content:""}]})]),e(s,{"previous-route":"keiri2024b","next-route":"keiri2023a"})])]),_:1}))}};export{P as default};
